import json
import subprocess
import os
from google.cloud import storage

def process_image(request):
    """Cloud Function triggered by Cloud Storage to convert images using ImageMagick."""
    
    # Get the event data
    if request.method == 'POST':
        try:
            # Parse the request data
            request_json = request.get_json(silent=True)
            
            # Extract bucket and file name from event
            bucket_name = request_json['bucket']
            file_name = request_json['name']
            
            # Extract conversion options from metadata
            metadata = request_json.get('metadata', {})
            conversion_options = metadata.get('conversion_options', '')
            
            # Validate conversion options to prevent command injection
            if not is_safe_conversion_options(conversion_options):
                return 'Invalid conversion options', 400
            
            # Get the full file path
            source_path = f"/tmp/{file_name}"
            
            # Download file from Cloud Storage
            storage_client = storage.Client()
            bucket = storage_client.bucket(bucket_name)
            blob = bucket.blob(file_name)
            blob.download_to_filename(source_path)
            
            # Build convert command with validation
            command = ['convert', source_path]
            
            # Add conversion options if provided
            if conversion_options:
                # Split options safely and validate each part
                options = conversion_options.split()
                for option in options:
                    if not is_safe_option(option):
                        return 'Invalid conversion option', 400
                command.extend(options)
            
            # Add output path
            output_path = source_path.replace('.jpg', '_converted.jpg')
            command.append(output_path)
            
            # Execute the convert command
            result = subprocess.call(command)
            
            if result == 0:
                # Upload converted file back to Cloud Storage
                converted_blob_name = file_name.replace('.jpg', '_converted.jpg')
                converted_blob = bucket.blob(converted_blob_name)
                converted_blob.upload_from_filename(output_path)
                
                # Clean up temporary files
                os.remove(source_path)
                os.remove(output_path)
                
                return 'Image processed successfully', 200
            else:
                return 'Image processing failed', 500
                
        except Exception as e:
            return f'Error processing image: {str(e)}', 500
    else:
        return 'Method not allowed', 405

def is_safe_conversion_options(options):
    """Validate that conversion options don't contain malicious commands."""
    if not options:
        return True
    
    # Only allow alphanumeric, spaces, and common image processing options
    allowed_chars = set('abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789-_. ')
    return all(c in allowed_chars for c in options)

def is_safe_option(option):
    """Validate individual conversion option."""
    # Only allow safe options that don't contain command injection
    safe_prefixes = ['-', '+', 'resize', 'quality', 'format', 'colorspace', 'strip']
    
    if option.startswith('--'):
        return False  # Long form options not allowed
    
    if option.startswith('-'):
        # Check if it's a known safe short option
        short_option = option[1:]
        if short_option in ['resize', 'quality', 'format', 'colorspace', 'strip']:
            return True
        return False
    
    # Allow numeric values and basic formatting
    if option.replace('.', '').isdigit():
        return True
    
    return True